v=Vector((3,2))
M=Midpoint(A,B)
P=Reflect(A, Line(B,C))
Q=Rotate(A, 30deg, O)
R=(x(K)+2*cos(t), y(K)+2*sin(t))

## 2. 线 / 圆 / 多边形
l=Line(A,B)
l=Line((0,c),(c,0))
l=Line(P, Vector((1,-1)))
s=Segment(A,B)
c=Circle((0,0),2)
c=Circle(A,B,C)
poly=Polygon(A,B,C,D)

## 3. 函数 / 曲线
f(x)=x^2
g(x)=sin(x)/x
h(x)=If(x<0, -x, x^2)
